"use client";

import { memo, useId, useMemo } from "react";
import {
  DEFAULT_EVENT_CARD_LABELS,
  type EventCard01Props,
  type EventCard01Labels,
} from "./types";
import { getEventStatus } from "./lib/event-status";
import { getDaysUntilEvent, formatEventDate } from "./lib/format-default";
import { EventCardGrid } from "./parts/grid";
import { EventCardFeed } from "./parts/feed";
import { EventCardList } from "./parts/list";
import { EventCardCompact } from "./parts/compact";

function EventCard01Inner({
  event,
  variant,
  href,
  getHref,
  onClick,
  linkComponent = "a",
  formatDate,
  now,
  statusOverride,
  labels: labelsProp,
  typeStyles,
  titleClassName,
  imageClassName,
  className,
  ariaLabel,
  actions,
  loading = "lazy",
}: EventCard01Props) {
  const titleId = useId();

  const labels = useMemo<Required<EventCard01Labels>>(
    () => ({ ...DEFAULT_EVENT_CARD_LABELS, ...labelsProp }),
    [labelsProp],
  );

  const status = useMemo(
    () => statusOverride ?? getEventStatus(event, now),
    [event, now, statusOverride],
  );

  const daysUntil = useMemo(
    () => getDaysUntilEvent(event.date, now),
    [event.date, now],
  );

  const formattedDate = useMemo(
    () => (formatDate ? formatDate(event.date) : formatEventDate(event.date)),
    [event.date, formatDate],
  );

  const resolvedHref =
    href ?? (getHref ? getHref(event) : undefined) ?? "#";

  const typeStyle = typeStyles?.[event.type];
  const featured = event.featured === true;

  const sharedProps = {
    event,
    status,
    daysUntil,
    formattedDate,
    featured,
    labels,
    href: resolvedHref,
    linkComponent,
    onClick,
    ariaLabel,
    titleId,
    titleClassName,
    imageClassName,
    className,
    actions,
    loading,
  };

  if (variant === "feed") {
    return <EventCardFeed {...sharedProps} />;
  }

  if (variant === "list") {
    return <EventCardList {...sharedProps} typeStyle={typeStyle} />;
  }

  if (variant === "compact") {
    return <EventCardCompact {...sharedProps} typeStyle={typeStyle} />;
  }

  return <EventCardGrid {...sharedProps} typeStyle={typeStyle} />;
}

export const EventCard01 = memo(EventCard01Inner);
EventCard01.displayName = "EventCard01";

export default EventCard01;

export { EventCard01, default } from "./event-card-01";

export type {
  EventCardItem,
  EventCard01Labels,
  EventCard01Props,
  EventCard01Variant,
  EventStatus,
} from "./types";

export { DEFAULT_EVENT_CARD_LABELS } from "./types";

export {
  getEventStatus,
  EVENT_STATUS_CONFIG,
  type EventStatusConfigEntry,
} from "./lib/event-status";

export { formatEventDate, getDaysUntilEvent } from "./lib/format-default";

export { meta } from "./meta";

import type { ElementType, MouseEvent, ReactNode } from "react";
import type { EventStatus } from "./lib/event-status";

export type { EventStatus };

export type EventCard01Variant = "grid" | "feed" | "list" | "compact";

export interface EventCardItem {
  /** Stable identifier. Used for React keys and the default ariaLabel. */
  id: string;
  /** Headline. Rendered as <h3>. Required. */
  title: string;
  /** Event-type label (e.g. "Conference", "Webinar"). Used as a key into `typeStyles`. Required. */
  type: string;
  /** Start date. ISO-8601 string parseable by `new Date()`. Required — drives status logic. */
  date: string;
  /** End date. ISO-8601 string. Optional — defaults to `date` (single-day event). */
  endDate?: string;
  /** Time string ("09:00 - 18:00"). Optional — meta line omitted if missing. */
  time?: string;
  /** Location string ("Istanbul Conference Center", "Virtual", etc). Optional. */
  location?: string;
  /** Image URL. Optional — placeholder rendered if missing. */
  image?: string;
  /** Image alt-text. Optional — falls back to `title`. */
  imageAlt?: string;
  /** Short summary. Optional — variant gracefully omits. */
  description?: string;
  /** Total seat count. Optional — capacity bar + capacity-derived states (full / lastSpots) skipped if absent. */
  capacity?: number;
  /** Currently-registered count. Optional — same as `capacity`. */
  registered?: number;
  /** Promotional flag. Optional — adds visual lift treatment. */
  featured?: boolean;
}

export interface EventCard01Labels {
  // ─── Status badges ──────────────────────────────────────────────
  /** Default: 'Ended'. */
  expired?: string;
  /** Default: 'Live now'. */
  ongoing?: string;
  /** Default: 'Soon'. */
  upcoming?: string;
  /** Default: 'Registration open'. */
  open?: string;
  /** Default: 'Sold out'. */
  full?: string;
  /** Default: 'Last spots'. */
  lastSpots?: string;
  // ─── Image-area overlays ────────────────────────────────────────
  /** Suffix on the days-until countdown. Default: 'days left'. */
  daysUntilSuffix?: string;
  /** Pulsing-dot pill text on `ongoing` events. Default: 'Happening now'. */
  ongoingIndicator?: string;
  // ─── Capacity counter ───────────────────────────────────────────
  /** Suffix on the spots-left counter. Default: 'spots left'. */
  spotsLeftSuffix?: string;
  /** Spots-left counter when capacity hit. Default: 'Sold out'. */
  spotsLeftFull?: string;
  /** aria-label prefix on the capacity progress bar. Default: 'Registered'. */
  capacityAriaPrefix?: string;
  /** Word between the registered + capacity numbers in the aria-label. Default: 'of'. */
  capacityAriaSeparator?: string;
  // ─── CTA ────────────────────────────────────────────────────────
  /** Default: 'Register'. */
  ctaRegister?: string;
  /** Default: 'Join'. */
  ctaJoin?: string;
  /** Default: 'View details'. */
  ctaViewDetails?: string;
  /** Default: 'Sold out'. */
  ctaSoldOut?: string;
  // ─── A11y ───────────────────────────────────────────────────────
  /** sr-only label on the featured-star icon. Default: 'Featured event'. */
  featuredAriaLabel?: string;
}

export interface EventCard01Props {
  /** The event to render. */
  event: EventCardItem;

  /** Visual variant. Required — no default; explicit per render site. */
  variant: EventCard01Variant;

  // ─── Navigation ──────────────────────────────────────────────────
  /** URL the card links to. Mutually exclusive with `getHref`. */
  href?: string;
  /** Alternative href derivation. Receives the event, returns a URL. */
  getHref?: (event: EventCardItem) => string;
  /** Click handler, fired before navigation if href is also set. */
  onClick?: (event: EventCardItem, mouseEvent: MouseEvent) => void;
  /** Element used for the link. Default: 'a'. Pass NextLink / RemixLink / etc. */
  linkComponent?: ElementType;

  // ─── Time / formatting ───────────────────────────────────────────
  /** Custom date formatter. Default: browser locale long format. */
  formatDate?: (dateString: string) => string;
  /** Inject a "now" reference for deterministic status (tests, live clocks). Default: new Date() at render. */
  now?: Date;
  /** Override the derived status. Rare — for preview / what-if states. */
  statusOverride?: EventStatus;
  /** Localized labels. Defaults are English. */
  labels?: EventCard01Labels;

  // ─── Theming ─────────────────────────────────────────────────────
  /** Map of event-type → Tailwind class string. Default: empty (falls to bg-muted). */
  typeStyles?: Record<string, { className: string }>;
  /** Override classes for the title. */
  titleClassName?: string;
  /** Override classes for the image. */
  imageClassName?: string;
  /** Override classes for the root <article>. */
  className?: string;

  // ─── Accessibility ───────────────────────────────────────────────
  /** Override the link's accessible name. Default: title. */
  ariaLabel?: string;

  // ─── Nested interactives (overlay-link pattern) ──────────────────
  /** Optional cluster of buttons/links that sit ABOVE the link overlay (z-10). */
  actions?: ReactNode;

  // ─── Performance ─────────────────────────────────────────────────
  /** Image loading strategy. Default: 'lazy'. */
  loading?: "lazy" | "eager";
}

/** Default English labels — exported for consumer composition. */
export const DEFAULT_EVENT_CARD_LABELS: Required<EventCard01Labels> = {
  expired: "Ended",
  ongoing: "Live now",
  upcoming: "Soon",
  open: "Registration open",
  full: "Sold out",
  lastSpots: "Last spots",
  daysUntilSuffix: "days left",
  ongoingIndicator: "Happening now",
  spotsLeftSuffix: "spots left",
  spotsLeftFull: "Sold out",
  capacityAriaPrefix: "Registered",
  capacityAriaSeparator: "of",
  ctaRegister: "Register",
  ctaJoin: "Join",
  ctaViewDetails: "View details",
  ctaSoldOut: "Sold out",
  featuredAriaLabel: "Featured event",
};

"use client";

import type { ElementType, MouseEvent, ReactNode } from "react";
import { Calendar, Clock, MapPin, Star, Users } from "lucide-react";
import { Progress } from "@/components/ui/progress";
import { buttonVariants } from "@/components/ui/button";
import { cn } from "@/lib/utils";
import type {
  EventCard01Labels,
  EventCardItem,
} from "../types";
import {
  EVENT_STATUS_CONFIG,
  type EventStatus,
} from "../lib/event-status";
import { ImageFallback } from "../lib/image-fallback";

interface GridPartProps {
  event: EventCardItem;
  status: EventStatus;
  daysUntil: number;
  formattedDate: string;
  typeStyle: { className: string } | undefined;
  featured: boolean;
  labels: Required<EventCard01Labels>;
  href: string;
  linkComponent: ElementType;
  onClick?: (event: EventCardItem, mouseEvent: MouseEvent) => void;
  ariaLabel?: string;
  titleId: string;
  titleClassName?: string;
  imageClassName?: string;
  className?: string;
  actions?: ReactNode;
  loading: "lazy" | "eager";
}

function resolveCta(
  status: EventStatus,
  labels: Required<EventCard01Labels>,
): { label: string; variant: "default" | "secondary" | "outline" } {
  switch (status) {
    case "ongoing":
      return { label: labels.ctaJoin, variant: "default" };
    case "full":
      return { label: labels.ctaSoldOut, variant: "secondary" };
    case "expired":
      return { label: labels.ctaViewDetails, variant: "outline" };
    case "open":
    case "upcoming":
    case "lastSpots":
    default:
      return { label: labels.ctaRegister, variant: "default" };
  }
}

export function EventCardGrid({
  event,
  status,
  daysUntil,
  formattedDate,
  typeStyle,
  featured,
  labels,
  href,
  linkComponent: LinkComponent,
  onClick,
  ariaLabel,
  titleId,
  titleClassName,
  imageClassName,
  className,
  actions,
  loading,
}: GridPartProps) {
  const statusEntry = EVENT_STATUS_CONFIG[status];
  const StatusIcon = statusEntry.icon;
  const showCapacity = event.capacity != null && event.registered != null;
  const spotsLeft = showCapacity
    ? (event.capacity ?? 0) - (event.registered ?? 0)
    : 0;
  const percentFull = showCapacity
    ? event.capacity === 0
      ? 100
      : ((event.registered ?? 0) / (event.capacity ?? 1)) * 100
    : 0;
  const cta = resolveCta(status, labels);
  const hasActions = actions != null;

  const handleClick = onClick
    ? (e: MouseEvent<HTMLAnchorElement>) => onClick(event, e)
    : undefined;

  return (
    <article
      className={cn(
        "relative group bg-card rounded-2xl overflow-hidden shadow-sm motion-safe:hover:shadow-xl transition-all duration-500 border border-border/50 h-full flex flex-col",
        statusEntry.cardClassName,
        featured && "border-t-4 border-t-primary",
        className,
      )}
    >
      {/* Image area */}
      <div className="relative h-48 overflow-hidden">
        {event.image ? (
          <img
            src={event.image}
            alt={event.imageAlt ?? event.title}
            loading={loading}
            className={cn(
              "w-full h-full object-cover motion-safe:group-hover:scale-110 transition-transform duration-700",
              imageClassName,
            )}
          />
        ) : (
          <ImageFallback className={imageClassName} />
        )}

        {/* Gradient overlay for legibility */}
        <div
          aria-hidden="true"
          className="absolute inset-0 bg-linear-to-t from-black/60 via-transparent to-transparent"
        />

        {/* Status badge — top-left */}
        <span
          className={cn(
            "absolute top-4 left-4 inline-flex items-center gap-1.5 px-3 py-1 rounded-md text-xs font-medium",
            statusEntry.className,
          )}
        >
          <StatusIcon aria-hidden="true" className="w-3.5 h-3.5" />
          {labels[status]}
        </span>

        {/* Type badge — top-right OR bottom-right when actions yields top */}
        <span
          className={cn(
            "absolute backdrop-blur-sm border rounded-md text-xs px-2.5 py-0.5",
            hasActions ? "bottom-4 right-4" : "top-4 right-4",
            typeStyle?.className ?? "bg-muted text-muted-foreground border-border",
          )}
        >
          {event.type}
        </span>

        {/* Actions slot — top-right, above link overlay */}
        {hasActions && (
          <div className="absolute top-4 right-4 z-10 flex gap-1.5">
            {actions}
          </div>
        )}

        {/* Days-until OR ongoing pill — bottom-left */}
        {status !== "expired" && status !== "ongoing" && (
          <div className="absolute bottom-4 left-4 bg-black/70 backdrop-blur-sm rounded-lg px-3 py-2 text-white">
            <div className="text-2xl font-bold leading-none">{daysUntil}</div>
            <div className="text-xs text-white/70">{labels.daysUntilSuffix}</div>
          </div>
        )}
        {status === "ongoing" && (
          <div className="absolute bottom-4 left-4 bg-accent/90 backdrop-blur-sm rounded-lg px-3 py-2 text-accent-foreground inline-flex items-center gap-2">
            <span
              aria-hidden="true"
              className="w-2 h-2 rounded-full bg-current motion-safe:animate-pulse"
            />
            <span className="text-sm font-medium">{labels.ongoingIndicator}</span>
          </div>
        )}
      </div>

      {/* Link overlay — covers whole article, transparent, on top of content */}
      <LinkComponent
        href={href}
        aria-labelledby={ariaLabel ? undefined : titleId}
        aria-label={ariaLabel}
        onClick={handleClick}
        className="absolute inset-0 z-0 rounded-2xl focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 outline-none"
      />

      {/* Content */}
      <div className="p-6 flex-1 flex flex-col">
        <h3
          id={titleId}
          className={cn(
            "text-xl font-bold text-foreground mb-2 motion-safe:group-hover:text-primary transition-colors line-clamp-2",
            titleClassName,
          )}
        >
          {featured && (
            <Star
              aria-hidden="true"
              className="inline w-4 h-4 fill-primary text-primary mr-1.5 align-baseline"
            />
          )}
          {event.title}
          {featured && (
            <span className="sr-only"> ({labels.featuredAriaLabel})</span>
          )}
        </h3>

        {event.description && (
          <p className="text-muted-foreground text-sm mb-4 line-clamp-2">
            {event.description}
          </p>
        )}

        {/* Meta lines */}
        <ul role="list" className="space-y-2 mb-4">
          <li className="flex items-center gap-2 text-sm text-muted-foreground">
            <Calendar
              aria-hidden="true"
              className="w-4 h-4 text-primary shrink-0"
            />
            <span>{formattedDate}</span>
          </li>
          {event.time && (
            <li className="flex items-center gap-2 text-sm text-muted-foreground">
              <Clock
                aria-hidden="true"
                className="w-4 h-4 text-primary shrink-0"
              />
              <span>{event.time}</span>
            </li>
          )}
          {event.location && (
            <li className="flex items-center gap-2 text-sm text-muted-foreground">
              <MapPin
                aria-hidden="true"
                className="w-4 h-4 text-primary shrink-0"
              />
              <span className="truncate">{event.location}</span>
            </li>
          )}
        </ul>

        {/* Capacity bar */}
        {showCapacity && (
          <div className="mt-auto">
            <div className="flex items-center justify-between text-sm mb-2">
              <span className="inline-flex items-center gap-1.5 text-muted-foreground">
                <Users aria-hidden="true" className="w-4 h-4" />
                {event.registered} / {event.capacity}
              </span>
              {status !== "expired" && (
                <span
                  className={cn(
                    "text-xs font-medium",
                    spotsLeft <= 5 && spotsLeft > 0
                      ? "text-destructive"
                      : "text-muted-foreground",
                  )}
                >
                  {spotsLeft > 0
                    ? `${spotsLeft} ${labels.spotsLeftSuffix}`
                    : labels.spotsLeftFull}
                </span>
              )}
            </div>
            <Progress
              value={percentFull}
              className={cn("h-2", status === "expired" && "opacity-50")}
              aria-label={`${labels.capacityAriaPrefix}: ${event.registered} ${labels.capacityAriaSeparator} ${event.capacity}`}
            />
          </div>
        )}

        {/* Decorative CTA — visual only; click passes through to link overlay */}
        <div
          aria-hidden="true"
          className={cn(
            buttonVariants({ variant: cta.variant }),
            "w-full mt-4 pointer-events-none",
            !showCapacity && "mt-auto",
          )}
        >
          {cta.label}
        </div>
      </div>
    </article>
  );
}

"use client";

import type { ElementType, MouseEvent, ReactNode } from "react";
import {
  ArrowRight,
  Calendar,
  Clock,
  MapPin,
  Star,
  Users,
} from "lucide-react";
import { buttonVariants } from "@/components/ui/button";
import { cn } from "@/lib/utils";
import type {
  EventCard01Labels,
  EventCardItem,
} from "../types";
import {
  EVENT_STATUS_CONFIG,
  type EventStatus,
} from "../lib/event-status";
import { ImageFallback } from "../lib/image-fallback";

interface FeedPartProps {
  event: EventCardItem;
  status: EventStatus;
  daysUntil: number;
  formattedDate: string;
  featured: boolean;
  labels: Required<EventCard01Labels>;
  href: string;
  linkComponent: ElementType;
  onClick?: (event: EventCardItem, mouseEvent: MouseEvent) => void;
  ariaLabel?: string;
  titleId: string;
  titleClassName?: string;
  imageClassName?: string;
  className?: string;
  actions?: ReactNode;
  loading: "lazy" | "eager";
}

function resolveCta(
  status: EventStatus,
  labels: Required<EventCard01Labels>,
): { label: string; variant: "default" | "secondary" | "outline" } {
  switch (status) {
    case "ongoing":
      return { label: labels.ctaJoin, variant: "default" };
    case "full":
      return { label: labels.ctaSoldOut, variant: "secondary" };
    case "expired":
      return { label: labels.ctaViewDetails, variant: "outline" };
    case "open":
    case "upcoming":
    case "lastSpots":
    default:
      return { label: labels.ctaRegister, variant: "default" };
  }
}

export function EventCardFeed({
  event,
  status,
  daysUntil,
  formattedDate,
  featured,
  labels,
  href,
  linkComponent: LinkComponent,
  onClick,
  ariaLabel,
  titleId,
  titleClassName,
  imageClassName,
  className,
  actions,
  loading,
}: FeedPartProps) {
  const statusEntry = EVENT_STATUS_CONFIG[status];
  const StatusIcon = statusEntry.icon;
  const showCapacity = event.capacity != null && event.registered != null;
  const spotsLeft = showCapacity
    ? (event.capacity ?? 0) - (event.registered ?? 0)
    : null;
  const cta = resolveCta(status, labels);
  const hasActions = actions != null;

  const handleClick = onClick
    ? (e: MouseEvent<HTMLAnchorElement>) => onClick(event, e)
    : undefined;

  return (
    <article
      className={cn(
        "relative group h-64 md:h-72 overflow-hidden lg:rounded-xl shadow-[inset_0_80px_60px_-40px_rgba(0,0,0,0.4)]",
        statusEntry.cardClassName,
        featured && "ring-2 ring-primary ring-inset",
        className,
      )}
    >
      {/* Background image */}
      {event.image ? (
        <img
          src={event.image}
          alt={event.imageAlt ?? event.title}
          loading={loading}
          className={cn(
            "absolute inset-0 w-full h-full object-cover motion-safe:group-hover:scale-105 transition-transform duration-700",
            imageClassName,
          )}
        />
      ) : (
        <ImageFallback className={cn("absolute inset-0", imageClassName)} />
      )}

      {/* Two layered gradients for depth + legibility */}
      <div
        aria-hidden="true"
        className="absolute inset-0 bg-linear-to-t from-black/90 via-black/50 to-black/30"
      />
      <div
        aria-hidden="true"
        className="absolute inset-0 shadow-[inset_0_60px_80px_-20px_rgba(0,0,0,0.6)]"
      />

      {/* Link overlay — covers whole card */}
      <LinkComponent
        href={href}
        aria-labelledby={ariaLabel ? undefined : titleId}
        aria-label={ariaLabel}
        onClick={handleClick}
        className="absolute inset-0 z-0 lg:rounded-xl focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 outline-none"
      />

      {/* Content */}
      <div className="absolute inset-0 flex flex-col justify-between p-6">
        {/* Top row */}
        <div className="flex items-start justify-between">
          <div className="flex items-center gap-2">
            <span
              className={cn(
                "inline-flex items-center gap-1.5 px-3 py-1 rounded-md text-xs font-medium",
                statusEntry.className,
              )}
            >
              <StatusIcon aria-hidden="true" className="w-3.5 h-3.5" />
              {labels[status]}
            </span>
            <span className="bg-white/10 text-white border border-white/20 backdrop-blur-sm rounded-md text-xs px-2.5 py-0.5">
              {event.type}
            </span>
          </div>

          {hasActions ? (
            <div className="z-10 flex gap-1.5">{actions}</div>
          ) : status === "ongoing" ? (
            <div className="bg-accent/90 backdrop-blur-sm rounded-full px-3 py-1.5 text-accent-foreground inline-flex items-center gap-2">
              <span
                aria-hidden="true"
                className="w-2 h-2 rounded-full bg-current motion-safe:animate-pulse"
              />
              <span className="text-xs font-medium">
                {labels.ongoingIndicator}
              </span>
            </div>
          ) : status !== "expired" ? (
            <div className="bg-white/10 backdrop-blur-md rounded-lg px-3 py-2 text-center">
              <div className="text-2xl font-bold text-white leading-none">
                {daysUntil}
              </div>
              <div className="text-xs text-white/70">
                {labels.daysUntilSuffix}
              </div>
            </div>
          ) : null}
        </div>

        {/* Bottom block */}
        <div>
          <h3
            id={titleId}
            className={cn(
              "text-xl md:text-2xl font-bold text-white mb-3 line-clamp-2 motion-safe:group-hover:text-accent transition-colors",
              titleClassName,
            )}
          >
            {featured && (
              <Star
                aria-hidden="true"
                className="inline w-4 h-4 fill-primary text-primary mr-1.5 align-baseline"
              />
            )}
            {event.title}
            {featured && (
              <span className="sr-only"> ({labels.featuredAriaLabel})</span>
            )}
          </h3>

          {/* Inline meta row */}
          <ul
            role="list"
            className="flex flex-wrap items-center gap-x-4 gap-y-2 text-sm text-white/80 mb-4"
          >
            <li className="flex items-center gap-1.5">
              <Calendar aria-hidden="true" className="w-4 h-4" />
              <span>{formattedDate}</span>
            </li>
            {event.time && (
              <li className="flex items-center gap-1.5">
                <Clock aria-hidden="true" className="w-4 h-4" />
                <span>{event.time}</span>
              </li>
            )}
            {event.location && (
              <li className="flex items-center gap-1.5">
                <MapPin aria-hidden="true" className="w-4 h-4" />
                <span className="truncate max-w-[150px]">{event.location}</span>
              </li>
            )}
            {showCapacity && (
              <li className="flex items-center gap-1.5">
                <Users aria-hidden="true" className="w-4 h-4" />
                <span>
                  {spotsLeft != null && spotsLeft > 0
                    ? `${spotsLeft} ${labels.spotsLeftSuffix}`
                    : labels.spotsLeftFull}
                </span>
              </li>
            )}
          </ul>

          {/* CTA + chevron */}
          <div className="flex items-center justify-between">
            <div
              aria-hidden="true"
              className={cn(
                buttonVariants({ variant: cta.variant, size: "sm" }),
                "pointer-events-none",
                status === "expired" &&
